import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const b=JSON.parse('{"title":"ReAct: Synergizing Reasoning and Acting in Language Models","description":"","frontmatter":{"title":"ReAct: Synergizing Reasoning and Acting in Language Models","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2210.03629-react-arxiv.md","filePath":"research/agent-harness/references/2210.03629-react-arxiv.md","lastUpdated":1779796674000}'),i={name:"research/agent-harness/references/2210.03629-react-arxiv.md"};function s(o,t,d,l,g,h){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="react-synergizing-reasoning-and-acting-in-language-models" tabindex="-1">ReAct: Synergizing Reasoning and Acting in Language Models <a class="header-anchor" href="#react-synergizing-reasoning-and-acting-in-language-models" aria-label="Permalink to &quot;ReAct: Synergizing Reasoning and Acting in Language Models&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">https://arxiv.org/abs/2210.03629</a></li><li><strong>發表</strong>: 2022-10（ICLR 2023）</li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority B — Agent harness 的理論基礎論文，所有 agentic loop 的根源</li></ul><hr><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p>定義 <strong>Thought-Action-Observation</strong> 的交錯迭代模式（ReAct = Reason + Act）。</p><table tabindex="0"><thead><tr><th>組成</th><th>說明</th><th>在 harness 中的對應</th></tr></thead><tbody><tr><td><strong>Reasoning traces</strong></td><td>內部思考，不影響外部狀態</td><td>LLM 的推理步驟、planning</td></tr><tr><td><strong>Actions</strong></td><td>與外部環境互動</td><td>工具呼叫、API 請求</td></tr><tr><td><strong>Observations</strong></td><td>行動的結果</td><td>工具回傳值、環境反饋</td></tr></tbody></table><h2 id="關鍵洞見" tabindex="-1">關鍵洞見 <a class="header-anchor" href="#關鍵洞見" aria-label="Permalink to &quot;關鍵洞見&quot;">​</a></h2><ul><li>推理幫助<strong>歸納、追蹤、更新</strong>行動計畫</li><li>行動帶來的 Observations 更新推理的前提</li><li>推理不影響外部狀態（純思考）；行動產生副作用</li></ul><h2 id="實驗成果" tabindex="-1">實驗成果 <a class="header-anchor" href="#實驗成果" aria-label="Permalink to &quot;實驗成果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>ReAct 提升</th><th>對比基線</th></tr></thead><tbody><tr><td>HotpotQA</td><td>超越 CoT</td><td>克服幻覺與誤差傳播</td></tr><tr><td>ALFWorld</td><td>+34% 絕對成功率</td><td>vs RL 方法</td></tr><tr><td>WebShop</td><td>+10% 絕對成功率</td><td>vs 其他 LLM 方法</td></tr></tbody></table><h2 id="對-harness-engineering-的意義" tabindex="-1">對 Harness Engineering 的意義 <a class="header-anchor" href="#對-harness-engineering-的意義" aria-label="Permalink to &quot;對 Harness Engineering 的意義&quot;">​</a></h2><ol><li><strong>Agentic Loop 的理論基礎</strong>: 所有現代 coding agent 都是 ReAct 的變體或組合</li><li><strong>Observation 是 Harness 的責任</strong>: 格式化工具輸出、過濾噪聲、注入 context</li><li><strong>Action 設計是工具設計</strong>: Tool schema 的精確度決定 Action 的成功率</li></ol><h2 id="歷史地位" tabindex="-1">歷史地位 <a class="header-anchor" href="#歷史地位" aria-label="Permalink to &quot;歷史地位&quot;">​</a></h2><p>ReAct 是從「LLM 作為問答機器」到「LLM 作為自主 agent」的轉折點。所有後續的 harness 設計（Plan-execute、Generate-test-repair、Tree search 等）都是 ReAct 的延伸與特化。</p><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv Abstract: <a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">https://arxiv.org/abs/2210.03629</a></li><li>GitHub: <a href="https://github.com/ysymyth/ReAct" target="_blank" rel="noreferrer">https://github.com/ysymyth/ReAct</a></li></ul>',16)])])}const u=e(i,[["render",s]]);export{b as __pageData,u as default};
